var shipments = app.MapGroup("api/shipments").RequireAuthorization();

shipments.MapGet("/", async (IShipmentService service) =>
    Results.Ok(await service.GetShipmentsAsync()));

shipments.MapGet("/{id:int}", async (int id, IShipmentService service) =>
    await service.GetShipmentByIdAsync(id) is { } shipment
        ? Results.Ok(shipment)
        : Results.NotFound());

shipments.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
    await service.GetShipmentByTrackingNumberAsync(trackingNumber) is { } shipment
        ? Results.Ok(shipment)
        : Results.NotFound());

shipments.MapPost("/", async (ShipmentDto dto, IShipmentService service) =>
{
    var created = await service.CreateShipmentAsync(dto);
    return Results.Created($"api/shipments/{created.Id}", created);
});

shipments.MapPut("/{id:int}", async (int id, ShipmentDto dto, IShipmentService service) =>
{
    dto.Id = id;
    return Results.Ok(await service.UpdateShipmentAsync(dto));
});

shipments.MapDelete("/{id:int}", async (int id, IShipmentService service) =>
{
    await service.DeleteShipmentAsync(id);
