    [Parameter]
    public int Id { get; set; }

    private ShipmentDto? shipment;
    private string? message;
    private bool isError;
    private bool saving;

    protected override async Task OnInitializedAsync()
    {
        shipment = await ShipmentService.GetShipmentByIdAsync(Id);
    }

    private async Task SaveAsync()
    {
        if (shipment is null) return;
        saving = true;
        try
        {
            shipment = await ShipmentService.UpdateShipmentAsync(shipment);
            message = "Shipment updated successfully.";
            isError = false;
        }
        catch (Exception ex)
        {
            message = $"Error saving: {ex.Message}";
            isError = true;
        }
        finally
        {
            saving = false;
        }
    }

    private async Task DeleteAsync()
    {
        if (shipment is null) return;
        saving = true;
        try
        {
            await ShipmentService.DeleteShipmentAsync(shipment.Id);
            Navigation.NavigateTo("/shipments");
        }
        catch (Exception ex)
        {
            message = $"Error deleting: {ex.Message}";
            isError = true;
            saving = false;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}
