            </div>
        </div>
    }
    else if (!FilteredShipments.Any())
    {
        <div class="alert alert-info">No shipments found.</div>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead class="table-dark">
                    <tr>
                        <th>Tracking #</th>
                        <th>Destination</th>
                        <th>Recipient</th>
                        <th>Status</th>
                        <th>Est. Delivery</th>
