// Shipment API endpoints (authenticated)
var shipments = app.MapGroup("api/shipments").RequireAuthorization();

shipments.MapGet("/", async (IShipmentService service) =>
    Results.Ok(await service.GetShipmentsAsync()));

shipments.MapGet("/{id:int}", async (int id, IShipmentService service) =>
    await service.GetShipmentByIdAsync(id) is { } shipment
        ? Results.Ok(shipment)
        : Results.NotFound());

