### 5. Server-side Service Implementation

Create `ShipmentTracker/Services/ShipmentServerService.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetShipmentsAsync()
    {
        return await db.Shipments
            .OrderByDescending(s => s.CreatedDate)
            .Select(s => ToDto(s))
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByIdAsync(int id)
    {
        var entity = await db.Shipments.FindAsync(id);
        return entity is null ? null : ToDto(entity);
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var entity = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return entity is null ? null : ToDto(entity);
    }

    public async Task<ShipmentDto> CreateShipmentAsync(ShipmentDto dto)
    {
        var entity = ToEntity(dto);
        entity.TrackingNumber = GenerateTrackingNumber();
        entity.CreatedDate = DateTime.UtcNow;
        db.Shipments.Add(entity);
        await db.SaveChangesAsync();
        return ToDto(entity);
    }

    public async Task<ShipmentDto> UpdateShipmentAsync(ShipmentDto dto)
    {
        var entity = await db.Shipments.FindAsync(dto.Id)
            ?? throw new KeyNotFoundException($"Shipment {dto.Id} not found");
        entity.Origin = dto.Origin;
        entity.Destination = dto.Destination;
        entity.Status = (int)dto.Status;
        entity.EstimatedDelivery = dto.EstimatedDelivery;
        entity.ActualDelivery = dto.ActualDelivery;
        entity.RecipientName = dto.RecipientName;
        entity.RecipientEmail = dto.RecipientEmail;
        entity.Description = dto.Description;
        entity.WeightKg = dto.WeightKg;

        if (dto.Status == ShipmentStatus.Delivered && entity.ActualDelivery is null)
            entity.ActualDelivery = DateTime.UtcNow;

        await db.SaveChangesAsync();
        return ToDto(entity);
    }

    public async Task DeleteShipmentAsync(int id)
    {
        var entity = await db.Shipments.FindAsync(id)
            ?? throw new KeyNotFoundException($"Shipment {id} not found");
        db.Shipments.Remove(entity);
        await db.SaveChangesAsync();
    }

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(100000, 999999)}";
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (ShipmentStatus)s.Status,
        CreatedDate = s.CreatedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        RecipientName = s.RecipientName,
        RecipientEmail = s.RecipientEmail,
        Description = s.Description,
        WeightKg = s.WeightKg
    };

    private static Shipment ToEntity(ShipmentDto d) => new()
    {
        Id = d.Id,
        TrackingNumber = d.TrackingNumber,
        Origin = d.Origin,
        Destination = d.Destination,
        Status = (int)d.Status,
        CreatedDate = d.CreatedDate,
        EstimatedDelivery = d.EstimatedDelivery,
        ActualDelivery = d.ActualDelivery,
        RecipientName = d.RecipientName,
        RecipientEmail = d.RecipientEmail,
        Description = d.Description,
        WeightKg = d.WeightKg
    };
}
```

